tavern_helper.content:
import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  ThongTinBangHoi: z.object({
    TenBangHoi: z.string(),
    TruongBangHoi: z.string(),
    ThietLapTheGioiQuan: z.string(),
    BoiCanhBangHoi: z.string(),
    PhongCachTuSu: z.string(),
    CheDoChoi: z.string(),
  }),
  TrangThaiGame: z.object({
    TaiSan: z.coerce.number(),
    DanhTieng: z.coerce.number(),
    MoTaDanhTieng: z.string(),
    ThuNhapHangNgay: z.coerce.number().optional(),
    DiemLenhToiDa: z.coerce.number(),
    DiemLenhHienTai: z.coerce.number(),
  }),
  TrangThaiTheGioi: z.object({
    NgayHienTai: z.string(),
    ThoiTiet: z.string(),
    ViTriHienTai: z.string(),
    SuKienToanCuc: z.object({
      Ten: z.string(),
      MoTa: z.string(),
      ThoiGianConLai: z.coerce.number(),
    }),
    TinTucGanDay: z.array(z.string()),
  }),
  ThanhVien: z.record(
    z.string().describe('ThanhVienID'),
    z.object({
      HoTen: z.string(),
      NgheNghiep: z.string(),
      GioiTinh: z.enum(['Nam', 'Nữ', 'Khac']),
      TrangThai: z.enum(['SanSang', 'BiThuong', 'DangLamNhiemVu', 'Chet', 'SuySout']),
      Luong: z.coerce.number(),
      SinhLuc: z.coerce.number(),
      SinhLucToiDa: z.coerce.number(),
      TriTue: z.coerce.number(),
      TriTueToiDa: z.coerce.number(),
      SucTanCong: z.coerce.number(),
      CapDo: z.coerce.number(),
      NhanTinhCach: z.array(z.string()),
      KhauHieu: z.string(),
      MucDoYeuThich: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      TrangBi: z.object({
        VuKhi: z.string(),
        Giap: z.string(),
        PhuKien: z.string(),
      }),
    }),
  ),
  NhiemVu: z.record(
    z.string().describe('NhiemVuID'),
    z.object({
      CapDo: z.enum(['S', 'A', 'B', 'C', 'D']),
      TieuDe: z.string(),
      MoTa: z.string(),
      DoChinhXacThongTin: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      Thuong: z.object({
        Von: z.coerce.number(),
        DanhTieng: z.coerce.number(),
      }),
    }),
  ),
  NhiemVuHienTai: z.object({
    CapDo: z.string(),
    TieuDe: z.string(),
    MoTa: z.string(),
    DonDoThucHien: z.string(),
    DoChinhXacThongTin: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
    TienDoNhiemVu: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
    MoTaTienDoNhiemVu: z.string(),
    Thuong: z.object({
      Von: z.coerce.number(),
      DanhTieng: z.coerce.number(),
    }),
  }),
  Doi: z.record(
    z.string().describe('DoiID'),
    z.object({
      TenDoi: z.string(),
      ThanhVienDoi: z.array(z.string()),
      MucDoAnY: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
      XepHangDoi: z.enum(['S', 'A', 'B', 'C', 'D']),
    }),
  ),
  CoSo: z.record(
    z.string().describe('CoSoID'),
    z.object({
      TenCoSo: z.string(),
      CapDo: z.coerce.number(),
      MoTaCapDoHienTai: z.string(),
      PhiNangCap: z.coerce.number(),
    }),
  ),
  BoSuuTap: z.record(
    z.string().describe('VatPhamID'),
    z.object({
      TenVatPham: z.string(),
      PhanLoai: z.enum(['VuKhi', 'Giap', 'PhuKien', 'DoLinhTinh', 'Khac']),
      CapDo: z.coerce.number(),
      MoTa: z.string(),
      ThayDoiThuocTinh: z.object({
        TanCong: z.coerce.number().optional(),
        SinhLucToiDa: z.coerce.number().optional(),
        TriTueToiDa: z.coerce.number().optional(),
      }),
      SoLuongConLai: z.coerce.number(),
    }),
  ),
  VatPhamChoDen: z.record(
    z.string().describe('VatPhamID'),
    z.object({
      TenVatPham: z.string(),
      PhanLoai: z.enum(['VuKhi', 'Giap', 'PhuKien', 'DoLinhTinh', 'Khac']),
      CapDo: z.coerce.number(),
      MoTa: z.string(),
      ThayDoiThuocTinh: z.object({
        TanCong: z.coerce.number().optional(),
        SinhLucToiDa: z.coerce.number().optional(),
        TriTueToiDa: z.coerce.number().optional(),
      }),
      GiaBan: z.coerce.number(),
    }),
  ),
  DanhSachCheTac: z.record(
    z.string().describe('VatPhamID'),
    z.object({
      TenVatPham: z.string(),
      PhanLoai: z.enum(['VuKhi', 'Giap', 'PhuKien', 'DoLinhTinh', 'Khac']),
      CapDo: z.coerce.number(),
      MoTa: z.string(),
      ThayDoiThuocTinh: z.object({
        TanCong: z.coerce.number().optional(),
        SinhLucToiDa: z.coerce.number().optional(),
        TriTueToiDa: z.coerce.number().optional(),
      }),
      PhiCheTac: z.coerce.number(),
    }),
  ),
  DanhSachGiaoTiep: z.record(
    z.string().describe('TheLucID'),
    z.object({
      TenTheLuc: z.string(),
      GioiThieuTheLuc: z.string(),
      CapDoTheLuc: z.coerce.number(),
      MucDoYeuThich: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      QuanHeHienTai: z.string(),
      ThuNhapGiaoTiepHangThang: z.coerce.number(),
      LanhDaoTheLuc: z
        .union([
          z.string().describe('ThanhVienID'),
          z.object({
            HoTen: z.string(),
            NgheNghiep: z.string(),
            GioiTinh: z.enum(['Nam', 'Nữ', 'Khac']),
            TrangThai: z.enum(['SanSang', 'BiThuong', 'DangLamNhiemVu', 'Chet', 'SuySout']),
            Luong: z.coerce.number(),
            SinhLuc: z.coerce.number(),
            SinhLucToiDa: z.coerce.number(),
            TriTue: z.coerce.number(),
            TriTueToiDa: z.coerce.number(),
            SucTanCong: z.coerce.number(),
            CapDo: z.coerce.number(),
            NhanTinhCach: z.array(z.string()),
            KhauHieu: z.string(),
            MucDoYeuThich: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
            TrangBi: z.object({
              VuKhi: z.string(),
              Giap: z.string(),
              PhuKien: z.string(),
            }),
          }),
        ])
        .optional(),
      AtChuTheLuc: z
        .union([
          z.string().describe('ThanhVienID'),
          z.object({
            HoTen: z.string(),
            NgheNghiep: z.string(),
            GioiTinh: z.enum(['Nam', 'Nữ', 'Khac']),
            TrangThai: z.enum(['SanSang', 'BiThuong', 'DangLamNhiemVu', 'Chet', 'SuySout']),
            Luong: z.coerce.number(),
            SinhLuc: z.coerce.number(),
            SinhLucToiDa: z.coerce.number(),
            TriTue: z.coerce.number(),
            TriTueToiDa: z.coerce.number(),
            SucTanCong: z.coerce.number(),
            CapDo: z.coerce.number(),
            NhanTinhCach: z.array(z.string()),
            KhauHieu: z.string(),
            MucDoYeuThich: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
            TrangBi: z.object({
              VuKhi: z.string(),
              Giap: z.string(),
              PhuKien: z.string(),
            }),
          }),
        ])
        .optional(),
    }),
  ),
});

$(() => {
  registerMvuSchema(Schema);
});

$(() => {
  // Xóa tầng trò chuyện ngoại trừ tầng cuối cùng
  $('#chat > .mes').not('.last_mes').remove();
  // Khi tệp trò chuyện thay đổi, tải lại giao diện hoặc tập lệnh
  let current_chat_id = SillyTavern.getCurrentChatId();
  eventOn(tavern_events.CHAT_CHANGED, chat_id => {
    if (current_chat_id !== chat_id) {
      current_chat_id = chat_id;
      reloadIframe();
    }
  })
})

entries.content:
{
  "name": "Mẫu sinh cốt truyện quản lý Guild",
  "description": "Dùng để hướng dẫn LLM tạo nội dung cốt truyện quản lý guild phù hợp với quy cách định dạng, bao gồm văn bản cốt truyện, thực thi nhiệm vụ, lựa chọn, tóm tắt và cập nhật biến",
  "version": "1.0.0",
  "template": {
    "instruction": "Bạn là người viết cốt truyện game chuyên nghiệp. Hãy dựa trên hành động, lựa chọn của người chơi và trạng thái game hiện tại, tạo ra sự phát triển cốt truyện hấp dẫn. Yêu cầu về giọng văn: điều chỉnh theo thế giới quan và phong cách tường thuật (lovecraftian nhấn mạnh nỗi sợ và điều bí ẩn, 80s-action nhấn mạnh sự cường điệu và bạo lực thẩm mỹ, corporate-isekai nhấn mạnh nơi làm việc và quan hệ con người, harem-novel nhấn mạnh ràng buộc cảm xúc), nhưng đừng lệch hướng, duy trì tính logic và đáng tin.",
    "output_format": {
      "order": ["<maintext>", "<mission>", "<option>", "<sum>", "<UpdateVariable>"],
      "maintext": {
        "description": "Văn bản cốt truyện, nếu vòng trước có lựa chọn của người chơi, có thể sử dụng cấu trúc ba đoạn;",
        "example": ""
      },
      "mission": {
        "description": "Cập nhật trạng thái nhiệm vụ (nếu có)"
      },
      "option": {
        "description": "Các lựa chọn được cung cấp cho người chơi, nên chứa ít nhất 2 lựa chọn có ý nghĩa (tránh các lựa chọn vô nghĩa)"
      },
      "sum": {
        "description": "Tổng kết vòng này, bao gồm sự kiện chính của vòng này",
        "format": "Định dạng: 【Tổng kết】+ Sự kiện chính"
      },
      "<UpdateVariable>": {
        "description": "Lệnh JSON Patch, dùng để cập nhật biến MVU"
      }
    }
  }
}

{
  "name": "Mẫu suy nghĩ CoT cho sinh cốt truyện quản lý Guild",
  "description": "Dùng để hướng dẫn LLM tiến hành suy nghĩ có hệ thống trước khi tạo cốt truyện quản lý guild, đảm bảo đầu ra phù hợp với quy cách định dạng và tính nhất quán logic. Điểm trọng tâm: Dựa trên thế giới quan và phong cách tường thuật để diễn giải các bầu không khí khác nhau; Dựa trên cách chơi game để xác định định vị vai trò của người chơi và trọng tâm cốt truyện (mô phỏng kinh doanh: người chơi không làm thành viên, cốt truyện xoay quanh quyết định kinh doanh; nhập vai: người chơi là thành viên, cốt truyện xoay quanh tham gia nhiệm vụ); Cơ chế vận hành guild (tài sản, uy tín, điểm lệnh); Cơ chế quản lý thành viên (HP, SP, trạng thái, trang bị); Cơ chế thực thi nhiệm vụ (tiến độ nhiệm vụ, độ chính xác tình báo, mức độ ăn ý của đội); Cơ chế nâng cấp cơ sở vật chất; Cơ chế nhận vật phẩm (chợ đen, chế tạo); Cơ chế quan hệ giữa các phe phái.",
  "version": "2.0.0",
  "cot_template": {
    "instruction": "Trước khi tạo nội dung cốt truyện, hãy tiến hành suy nghĩ có hệ thống sau. Viết quá trình suy nghĩ của bạn trong các thẻ <thinking> và </thinking>, sau đó xuất nội dung cốt truyện chính thức. ⚠️ Quan trọng: Phải nghiêm ngặt dựa trên cách chơi game đã chọn để xác định định vị vai trò của người chơi và trọng tâm cốt truyện: Nếu là mô hình mô phỏng kinh doanh, người chơi không làm thành viên, cốt truyện xoay quanh quyết định kinh doanh; Nếu là mô hình nhập vai, người chơi là thành viên, cốt truyện xoay quanh tham gia nhiệm vụ;"
  }
}

---
Quy tắc cập nhật biến số:
  ThongTinBangHoi:
    type: |-
      {
        TenBangHoi: string;
        ThietLapTheGioiQuan: string;
        BoiCanhBangHoi: string;
        PhongCachTuSu: string;
        CheDoChoi: string;
      }
    description:
      TenBangHoi: "Tên của bang hội, được thiết lập khi bắt đầu game, thường không thay đổi. Ví dụ: Bang hội Hành Trình Rạng Đông, Liên Minh Bóng Tối, v.v."
      ThietLapTheGioiQuan: "Thiết lập thế giới quan của trò chơi. Được thiết lập khi bắt đầu game, thường không thay đổi."
      BoiCanhBangHoi: "Thiết lập bối cảnh của bang hội. Được thiết lập khi bắt đầu game, thường không thay đổi."
      PhongCachTuSu: "Phong cách tự sự của trò chơi. Được thiết lập khi bắt đầu game, thường không thay đổi."
      CheDoChoi: "Chế độ chơi của trò chơi. Được thiết lập khi bắt đầu game, thường không thay đổi. Ví dụ: Mô phỏng quản lý, Nhập vai, v.v."
    check:
      - ThongTinBangHoi được thiết lập khi bắt đầu game, thường không thay đổi
      - Trừ khi cốt truyện liên quan đến tái cơ cấu bang hội, đổi tên hoặc các sự kiện lớn khác, nếu không thì không nên sửa đổi các trường này
  TrangThaiGame:
    type: |-
      {
        TaiSan: number;
        DanhTieng: number;
        MoTaDanhTieng: string;
        ThuNhapHangNgay?: number;
        DiemLenhToiDa: number;
        DiemLenhHienTai: number;
      }
    description:
      TaiSan: "Tài sản tiền mặt của bang hội, kiểu số. Thay đổi qua: hoàn thành nhiệm vụ nhận thưởng (+), trả lương thành viên (-), mua vật phẩm (-), nâng cấp cơ sở (-). Tối thiểu 0, không có giới hạn trên."
      DanhTieng: "Giá trị danh tiếng của bang hội, kiểu số. Được tăng hoặc giảm qua hoàn thành nhiệm vụ, tương tác với các phe phái. Không có giới hạn dưới, không có giới hạn trên."
      MoTaDanhTieng: "Mô tả địa vị và ảnh hưởng của bang hội trong thế giới dựa trên giá trị danh tiếng hiện tại. Cập nhật theo sự thay đổi giá trị danh tiếng, phản ánh tình trạng danh tiếng hiện tại của bang hội."
      ThuNhapHangNgay: "Thu nhập hàng ngày của bang hội, kiểu số (tùy chọn). Được tính dựa trên cơ sở vật chất, nhiệm vụ, quan hệ phe phái, v.v. Tự động cộng vào tài sản khi kết toán hàng ngày. Có thể là số dương (nhận tiền), 0 (không thu nhập) hoặc số âm (phải trả phí)."
      DiemLenhToiDa: "Số điểm lệnh tối đa có thể sử dụng mỗi lượt, kiểu số. Được thiết lập khi bắt đầu game, có thể tăng qua nâng cấp cơ sở."
      DiemLenhHienTai: "Số điểm lệnh còn lại trong lượt hiện tại, kiểu số. Được đặt lại về điểm lệnh tối đa vào đầu mỗi lượt, giảm khi sử dụng lệnh. Phạm vi [0, DiemLenhToiDa]"
    check:
      - Thay đổi tài sản: hoàn thành nhiệm vụ nhận thưởng (+), trả lương thành viên (-), mua vật phẩm (-), nâng cấp cơ sở (-), mua chợ đen (-), chế tạo vật phẩm (-), kết toán thu nhập hàng ngày (+)
      - Thay đổi danh tiếng: hoàn thành nhiệm vụ (+/-), tương tác với phe phái (+/-), sự kiện đặc biệt (+/-)
      - Cập nhật mô tả danh tiếng: theo sự thay đổi giá trị danh tiếng, cập nhật văn bản mô tả tương ứng
      - Tính thu nhập hàng ngày: dựa trên cơ sở vật chất, nhiệm vụ, quan hệ phe phái, v.v. Tự động cộng vào tài sản khi kết toán hàng ngày
      - Điểm lệnh: vào đầu mỗi lượt, `DiemLenhHienTai` được đặt lại về `DiemLenhToiDa`
      - Sử dụng điểm lệnh: khi thực hiện lệnh, `DiemLenhHienTai` giảm, không thể thấp hơn 0
      - Phải tính toán số liệu chính xác, tài sản không thể âm (trừ khi cốt truyện đặc biệt cho phép)
  TrangThaiTheGioi:
    type: |-
      {
        NgayHienTai: string;
        ThoiTiet: string;
        ViTriHienTai: string;
        SuKienToanCuc: {
          Ten: string;
          MoTa: string;
          ThoiGianConLai: number;
        };
        TinTucGanDay: string[];
      }
    description:
      NgayHienTai: "Ngày hiện tại trong game, định dạng: Năm X tháng X ngày X. Ví dụ: Năm 1 tháng 1 ngày 1, Năm 2 tháng 3 ngày 15, v.v. Cập nhật theo tiến trình game, mỗi lượt hoặc mỗi tháng."
      ThoiTiet: "Tình trạng thời tiết hiện tại của thế giới, kiểu chuỗi. Ví dụ: Nắng, Âm u, Mưa to, Bão tuyết, Sương mù, v.v. Cập nhật theo tiến trình game, mùa, sự kiện."
      ViTriHienTai: "Vị trí hiện tại của bang hội, kiểu chuỗi. Ví dụ: Thủ đô, Thị trấn biên giới, Thành phố trên không, Căn cứ dưới biển, v.v. Cập nhật theo tiến trình game, thực hiện nhiệm vụ, sự kiện di chuyển."
      SuKienToanCuc.Ten: "Tên sự kiện toàn cục đang diễn ra. Có thể là chuỗi rỗng (không có sự kiện toàn cục), hoặc tên sự kiện. Được thiết lập khi sự kiện xảy ra, xóa khi sự kiện kết thúc."
      SuKienToanCuc.MoTa: "Mô tả chi tiết sự kiện toàn cục hiện tại. Có thể là chuỗi rỗng (không có sự kiện toàn cục), hoặc mô tả sự kiện. Được thiết lập khi sự kiện xảy ra, xóa khi sự kiện kết thúc."
      SuKienToanCuc.ThoiGianConLai: "Thời gian còn lại của sự kiện toàn cục, kiểu số. Có thể là 0 (không có sự kiện), hoặc số ngày còn lại. Được thiết lập khi sự kiện xảy ra, giảm mỗi lượt hoặc mỗi tháng, đặt lại về 0 khi sự kiện kết thúc."
      TinTucGanDay: "Mảng tiêu đề tin tức gần đây, phần tử là chuỗi. Ghi lại các sự kiện và tin tức quan trọng gần đây. Cập nhật theo tiến trình game, có thể giới hạn số lượng tin (ví dụ: giữ 10 tin gần nhất)."
    check:
      - Tiến triển ngày tháng: vào đầu mỗi lượt hoặc mỗi tháng, cập nhật `NgayHienTai`, tăng ngày theo quy tắc tiến trình thời gian game
      - Cập nhật thời tiết: theo tiến trình game, mùa, sự kiện, v.v., cập nhật mô tả `ThoiTiet`
      - Cập nhật vị trí: theo tiến trình game, thực hiện nhiệm vụ, sự kiện di chuyển, v.v., cập nhật mô tả `ViTriHienTai`
      - Kích hoạt sự kiện toàn cục: khi sự kiện toàn cục được kích hoạt, thiết lập tất cả các trường của `SuKienToanCuc`, đặt `ThoiGianConLai` bằng thời gian kéo dài của sự kiện
      - Sự kiện toàn cục tiếp diễn: mỗi lượt hoặc mỗi tháng, `ThoiGianConLai` giảm, khi giảm về 0 thì xóa tất cả các trường của `SuKienToanCuc`
      - Kết thúc sự kiện toàn cục: khi sự kiện kết thúc, xóa tất cả các trường của `SuKienToanCuc` (đặt tên, mô tả thành chuỗi rỗng, đặt ThoiGianConLai về 0)
      - Cập nhật tin tức: khi có sự kiện quan trọng xảy ra, thêm tiêu đề tin mới vào đầu mảng `TinTucGanDay`, có thể giới hạn độ dài mảng (ví dụ: giữ 10 tin gần nhất)
      - Định dạng ngày tháng phải tuân theo "Năm X tháng X ngày X"
      - ThoiGianConLai không thể là số âm
  ThanhVien:
    type: |-
      Record<string, {
        HoTen: string;
        NgheNghiep: string;
        GioiTinh: 'Nam' | 'Nữ';
        TrangThai: 'SanSang' | 'BiThuong' | 'DangLamNhiemVu' | 'Chet' | 'SuySout';
        Luong: number;
        SinhLuc: number;
        SinhLucToiDa: number;
        TriTue: number;
        TriTueToiDa: number;
        SucTanCong: number;
        CapDo: number;
        NhanTinhCach: string[];
        KhauHieu: string;
        MucDoYeuThich: number;
        TrangBi: {
          VuKhi: string;
          Giap: string;
          PhuKien: string;
        };
      }>
    description:
      ThanhVienID: "Định danh duy nhất của thành viên, dùng làm khóa key của đối tượng, ví dụ: member_001, member_002. Dùng để phân biệt các thành viên khác nhau."
      HoTen: "Tên của thành viên, được thiết lập khi tạo nhân vật hoặc tuyển dụng, thường không thay đổi."
      NgheNghiep: "Nghề nghiệp của thành viên, được thiết lập khi tạo nhân vật hoặc tuyển dụng, thường không thay đổi. Ví dụ: Tiên phong xung kích, Lõi chiến thuật, Chỉ huy chiến lược, v.v."
      GioiTinh: "Giới tính của thành viên. Giá trị: Nam, Nữ, Khác. Được thiết lập khi tạo nhân vật hoặc tuyển dụng, thường không thay đổi."
      TrangThai: "Trạng thái hiện tại của thành viên. Giá trị: Sẵn sàng, Bị thương, Đang làm nhiệm vụ, Chết, Sụp đổ tinh thần. Cập nhật theo tiến trình game và sự kiện."
      Luong: "Lương mỗi lượt của thành viên, kiểu số. Được thiết lập khi tuyển dụng, có thể điều chỉnh qua đàm phán hợp đồng. Tối thiểu 0, không có giới hạn trên."
      SinhLuc: "Giá trị sinh lực hiện tại của thành viên, kiểu số. Bị thương (-), chữa trị (+), ảnh hưởng từ trang bị. Phạm vi [0, SinhLucToiDa]"
      SinhLucToiDa: "Giá trị sinh lực tối đa của thành viên, kiểu số. Được thiết lập khi tạo nhân vật hoặc tuyển dụng, bị ảnh hưởng bởi trang bị, cấp độ. Tối thiểu 1, không có giới hạn trên."
      TriTue: "Giá trị trí tuệ hiện tại của thành viên, kiểu số. Bị ảnh hưởng bởi sự kiện (-), nghỉ ngơi (+), trang bị ảnh hưởng. Phạm vi [0, TriTueToiDa]"
      TriTueToiDa: "Giá trị trí tuệ tối đa của thành viên, kiểu số. Được thiết lập khi tạo nhân vật hoặc tuyển dụng, bị ảnh hưởng bởi trang bị. Tối thiểu 1, không có giới hạn trên."
      SucTanCong: "Sức tấn công của thành viên, kiểu số. Được thiết lập khi tạo nhân vật hoặc tuyển dụng, bị ảnh hưởng bởi trang bị, cấp độ. Tối thiểu 0, không có giới hạn trên."
      CapDo: "Cấp độ của thành viên, kiểu số. Tăng qua hoàn thành nhiệm vụ, huấn luyện. Cấp độ ban đầu được thiết lập theo thiết kế nhân vật, sau đó cập nhật theo tình trạng phát triển của nhân vật. Tối thiểu 1, không có giới hạn trên."
      NhanTinhCach: "Mảng nhãn tính cách của thành viên, bao gồm tính cách, đặc điểm, bối cảnh, v.v. Được thiết lập khi tạo nhân vật hoặc tuyển dụng, thường không thay đổi, có thể thay đổi khi có sự kiện lớn. Ví dụ: ['Hung hăng', 'Kiên định', 'Cựu chiến binh huyền thoại', 'Thiên tài', 'Dị ăn', 'Chống đối xã hội', 'Hội chứng sợ xã hội', 'Workaholic', 'Rối loạn cưỡng chế', 'Tự kỷ', 'Đa hoạt động', 'Trầm cảm', 'Rối loạn lo âu']"
      KhauHieu: "Khẩu hiệu của thành viên, được thiết lập khi tạo nhân vật hoặc tuyển dụng, thường không thay đổi, có thể thay đổi khi có sự kiện lớn."
      MucDoYeuThich: "Số nguyên trong khoảng [-100,100], đại diện cho mức độ yêu thích của thành viên đối với người chơi. 0 là trung lập, giá trị dương là thân thiện, giá trị âm là thù địch. Thay đổi qua tương tác, nhiệm vụ, sự kiện. Được thiết lập giá trị ban đầu khi tạo nhân vật hoặc tuyển dụng, sau đó cập nhật theo tình hình tương tác."
      TrangBi.VuKhi: "Tên vũ khí hiện tại trang bị của thành viên, mặc định là chuỗi rỗng. Cập nhật khi trang bị vật phẩm, khôi phục thành chuỗi rỗng hoặc vũ khí mặc định khi gỡ trang bị."
      TrangBi.Giap: "Tên giáp bảo vệ hiện tại trang bị của thành viên, mặc định là chuỗi rỗng. Cập nhật khi trang bị vật phẩm, khôi phục thành chuỗi rỗng hoặc giáp mặc định khi gỡ trang bị."
      TrangBi.PhuKien: "Tên phụ kiện hiện tại trang bị của thành viên, mặc định là chuỗi rỗng. Cập nhật khi trang bị vật phẩm, khôi phục thành chuỗi rỗng hoặc phụ kiện mặc định khi gỡ trang bị."
    check:
      - Tạo nhân vật hoặc tuyển dụng: khởi tạo đối tượng thành viên, tạo khóa key thành viên theo cấu hình (ví dụ: member_001), điền tất cả các trường bao gồm giới tính, mức độ yêu thích, v.v.
      - Cập nhật trạng thái: theo sự kiện, hành động, nhiệm vụ cập nhật `TrangThai`, giá trị phải là một trong: Sẵn sàng, Bị thương, Đang làm nhiệm vụ, Chết, Sụp đổ tinh thần
      - Thay đổi mức độ yêu thích: qua tương tác (+/-), hoàn thành nhiệm vụ (+/-), sự kiện (+/-), phải nằm trong phạm vi [-100,100]
      - Thay đổi sinh lực: bị thương (-), chữa trị (+), trang bị ảnh hưởng (ảnh hưởng sinh lực tối đa)
      - Thay đổi trí tuệ: sự kiện kinh hoàng (-), áp lực (-), nghỉ ngơi (+), trang bị ảnh hưởng (ảnh hưởng trí tuệ tối đa)
      - Thay đổi sức tấn công: trang bị vũ khí (+/-), tăng cấp (+)
      - Tăng cấp: hoàn thành nhiệm vụ nhận kinh nghiệm (+), huấn luyện (+)
      - Cập nhật trang bị: khi trang bị vật phẩm, cập nhật trường trang bị tương ứng, đồng thời đồng bộ cập nhật sinh lực, trí tuệ, sức tấn công và các thuộc tính bị ảnh hưởng
      - Gỡ trang bị: khi gỡ trang bị, khôi phục trường trang bị, đồng thời đồng bộ cập nhật các thuộc tính bị ảnh hưởng
      - Phạm vi số liệu: sinh lực phải nằm trong phạm vi [0, SinhLucToiDa], trí tuệ phải nằm trong phạm vi [0, TriTueToiDa]
      - Liên kết trạng thái và số liệu: khi sinh lực bằng 0, `TrangThai` nên là 'Chết'; khi sinh lực quá thấp, `TrangThai` có thể chuyển thành 'Bị thương'
      - Xử lý khi chết: khi thành viên chết, đặt `TrangThai` thành 'Chết', đặt sinh lực về 0
      - Thanh toán lương: mỗi lượt thanh toán lương, trừ số tiền tương ứng từ `TrangThaiGame.TaiSan`
  NhiemVu:
    type: |-
      Record<string, {
        CapDo: 'S' | 'A' | 'B' | 'C' | 'D';
        TieuDe: string;
        MoTa: string;
        DoChinhXacThongTin: number;
        Thuong: {
          Von: number;
          DanhTieng: number;
        };
      }>
    description:
      NhiemVuID: "Định danh duy nhất của nhiệm vụ, dùng làm khóa key của đối tượng, ví dụ: mission_001, mission_002. Dùng để phân biệt các nhiệm vụ khác nhau."
      CapDo: "Cấp độ khó khăn của nhiệm vụ. Giá trị: S (Độ khó cao nhất, ảnh hưởng đến thế giới thậm chí vũ trụ), A (Độ khó cao, ảnh hưởng đến nhiều quốc gia thậm chí toàn thế giới), B (Độ khó trung bình-cao, ảnh hưởng đến một quốc gia thậm chí một lục địa), C (Độ khó trung bình, ảnh hưởng đến một hoặc nhiều thành phố), D (Độ khó thấp, ảnh hưởng đến một thành phố hoặc phạm vi nhỏ hơn). Được thiết lập khi tạo nhiệm vụ, thường không thay đổi."
      TieuDe: "Tiêu đề nhiệm vụ, được thiết lập khi tạo nhiệm vụ, thường không thay đổi."
      MoTa: "Mô tả chi tiết nhiệm vụ, được thiết lập khi tạo nhiệm vụ, thường không thay đổi. Mô tả nội dung, mục tiêu, rủi ro của nhiệm vụ."
      DoChinhXacThongTin: "Số nguyên trong khoảng [0,100], đại diện cho mức độ chính xác của tin tức nhiệm vụ. 0 là hoàn toàn sai, 100 là hoàn toàn chính xác. Được thiết lập khi tạo nhiệm vụ, thường không thay đổi."
      Thuong.Von: "Phần thưởng tiền khi hoàn thành nhiệm vụ, kiểu số. Được thiết lập khi tạo nhiệm vụ, thường không thay đổi."
      Thuong.DanhTieng: "Phần thưởng danh tiếng khi hoàn thành nhiệm vụ, kiểu số. Được thiết lập khi tạo nhiệm vụ, thường không thay đổi."
    check:
      - Tạo nhiệm vụ: khởi tạo đối tượng nhiệm vụ, tạo khóa key nhiệm vụ theo cấu hình (ví dụ: mission_001), điền tất cả các trường
      - Khi hoàn thành nhiệm vụ: xóa nhiệm vụ khỏi danh sách (xóa khóa key tương ứng)
      - Thông tin nhiệm vụ được thiết lập khi tạo, thường không thay đổi
      - Trừ khi có sự kiện đặc biệt như cập nhật tin tức nhiệm vụ, nếu không thì không nên sửa đổi các trường nhiệm vụ
  NhiemVuHienTai:
    type: |-
      {
        CapDo: string;
        TieuDe: string;
        MoTa: string;
        DonDoThucHien: string;
        DoChinhXacThongTin: number;
        TienDoNhiemVu: number;
        MoTaTienDoNhiemVu: string;
        Thuong: {
          Von: number;
          DanhTieng: number;
        };
      }
    description:
      CapDo: "Cấp độ khó của nhiệm vụ đang thực hiện. Có thể là chuỗi rỗng (chưa nhận nhiệm vụ), hoặc cấp độ nhiệm vụ (S, A, B, C, D). Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, xóa khi hoàn thành nhiệm vụ."
      TieuDe: "Tiêu đề nhiệm vụ đang thực hiện. Có thể là chuỗi rỗng (chưa nhận nhiệm vụ), hoặc tiêu đề nhiệm vụ. Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, xóa khi hoàn thành nhiệm vụ."
      MoTa: "Mô tả nhiệm vụ đang thực hiện. Có thể là chuỗi rỗng (chưa nhận nhiệm vụ), hoặc mô tả nhiệm vụ. Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, xóa khi hoàn thành nhiệm vụ."
      DonDoThucHien: "ID của đội đang thực hiện nhiệm vụ hiện tại. Có thể là chuỗi rỗng (chưa nhận nhiệm vụ), hoặc ID đội. Được thiết lập khi nhận nhiệm vụ, xóa khi hoàn thành nhiệm vụ."
      DoChinhXacThongTin: "Số nguyên trong khoảng [0,100], đại diện cho mức độ chính xác của tin tức nhiệm vụ. Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, đặt lại về 0 khi hoàn thành nhiệm vụ."
      TienDoNhiemVu: "Số nguyên trong khoảng [0,100], đại diện cho tiến độ hoàn thành nhiệm vụ. 0 là chưa bắt đầu, 100 là hoàn thành. Cập nhật theo tình hình thực hiện nhiệm vụ, đặt lại về 0 khi hoàn thành nhiệm vụ."
      MoTaTienDoNhiemVu: "Văn bản mô tả tiến độ nhiệm vụ hiện tại. Cập nhật theo tình hình thực hiện nhiệm vụ, phản ánh trạng thái hiện tại của nhiệm vụ, xóa khi hoàn thành nhiệm vụ."
      Thuong.Von: "Phần thưởng tiền khi hoàn thành nhiệm vụ. Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, đặt lại về 0 khi hoàn thành nhiệm vụ."
      Thuong.DanhTieng: "Phần thưởng danh tiếng khi hoàn thành nhiệm vụ. Được sao chép từ `NhiemVu` khi nhận nhiệm vụ, đặt lại về 0 khi hoàn thành nhiệm vụ."
    check:
      - Nhận nhiệm vụ: chọn nhiệm vụ từ `NhiemVu`, sao chép thông tin nhiệm vụ vào `NhiemVuHienTai`, thiết lập `DonDoThucHien`, đặt `TienDoNhiemVu` về 0
      - Cập nhật tiến độ nhiệm vụ: theo tình hình thực hiện nhiệm vụ, cập nhật `TienDoNhiemVu` và `MoTaTienDoNhiemVu`
      - Hoàn thành nhiệm vụ: cộng phần thưởng nhiệm vụ vào `TrangThaiGame.TaiSan` và `TrangThaiGame.DanhTieng`, xóa nhiệm vụ khỏi `NhiemVu`, xóa tất cả các trường của `NhiemVuHienTai`
      - Nhiệm vụ thất bại hoặc hủy: xóa tất cả các trường của `NhiemVuHienTai`
      - Tiến độ nhiệm vụ phải nằm trong phạm vi [0,100]
      - Duy trì tính hợp lý của cập nhật tiến độ nhiệm vụ, tránh tiến độ thoái lui hoặc nhảy vọt quá lớn
  Doi:
    type: |-
      Record<string, {
        TenDoi: string;
        ThanhVienDoi: string[];
        MucDoAnY: number;
        XepHangDoi: 'S' | 'A' | 'B' | 'C' | 'D';
      }>
    description:
      DoiID: "Định danh duy nhất của đội, dùng làm khóa key của đối tượng, ví dụ: squad_001, squad_002. Dùng để phân biệt các đội khác nhau."
      TenDoi: "Tên của đội, được thiết lập khi tạo đội, có thể thay đổi qua đổi tên."
      ThanhVienDoi: "Mảng ID thành viên đội, phần tử là khóa key của `ThanhVien`. Cập nhật khi tạo đội hoặc điều chỉnh thành viên."
      MucDoAnY: "Số nguyên trong khoảng [0,100], đại diện cho mức độ ăn ý giữa các thành viên trong đội. 0 là hoàn toàn không ăn ý, 100 là phối hợp hoàn hảo. Tăng qua cùng nhau thực hiện nhiệm vụ, huấn luyện."
      XepHangDoi: "Đánh giá tổng hợp của đội. Giá trị: S (Cao nhất), A (Cao), B (Trung), C (Thấp), D (Thấp nhất). Được tính toán tự động dựa trên thực lực thành viên, mức độ ăn ý, thường không cần sửa đổi thủ công."
    check:
      - Tạo đội: khởi tạo đối tượng đội, tạo khóa key đội theo cấu hình (ví dụ: squad_001), điền tất cả các trường, `ThanhVienDoi` khởi tạo là mảng rỗng hoặc mảng ID thành viên được chỉ định
      - Điều chỉnh thành viên: khi thêm hoặc xóa thành viên, cập nhật mảng `ThanhVienDoi`
      - Thay đổi mức độ ăn ý: cùng thực hiện nhiệm vụ (+), huấn luyện (+), nhiệm vụ thất bại (-)
      - Đánh giá đội: được tính toán tự động dựa trên thực lực thành viên, mức độ ăn ý, thường không cần cập nhật thủ công
